    let args = build_exec_args(opts);

    let log_file = std::fs::File::create(&opts.log)?;
    let log_err = log_file.try_clone()?;

    let mut cmd = std::process::Command::new(exe);
    cmd.args(&args)
        .stdin(Stdio::null())
        .stdout(log_file.into())
        .stderr(log_err.into());

    #[cfg(unix)]
    {
        use std::os::unix::process::CommandExt;
        unsafe {
            cmd.pre_exec(|| {
                libc::setsid();
                Ok(())
            });
        }
    }

    let child = cmd.spawn()?;
    eprintln!(
        "finalize: daemonized (pid {}), log: {}",
        child.id(),
        opts.log.display()
    );
    Ok(())
}

fn finalize(opts: &FinalizeOpts) -> Result<(), Box<dyn std::error::Error>> {
    if opts.foreground || opts.exec {
        finalize_exec(opts)
    } else {
        daemonize(opts)
    }
}

fn main() -> ExitCode {
    let cmd = match parse_args(std::env::args()) {
        Ok(cmd) => cmd,
        Err(e) => {
            eprintln!("error: {e}");
            return ExitCode::FAILURE;
        }
    };

    match cmd {
        Command::Version => {
            println!("vc-x1 {}", env!("CARGO_PKG_VERSION"));
            ExitCode::SUCCESS
        }
        Command::Help => {
            println!("{USAGE}");
            ExitCode::SUCCESS
        }
        Command::List { path } => {
            if let Err(e) = list(&path) {
                eprintln!("error: {e}");
                return ExitCode::FAILURE;
            }
            ExitCode::SUCCESS
        }
        Command::Finalize(opts) => {
            if let Err(e) = finalize(&opts) {
                eprintln!("error: {e}");
                return ExitCode::FAILURE;
            }
            ExitCode::SUCCESS
        }
    }
}

